import React, { useState } from 'react';
import API from '../services/api';

export default function AddCar(){
  const [model,setModel]=useState('');
  const [regNo,setRegNo]=useState('');
  const [fuel,setFuel]=useState('Petrol');
  const [year,setYear]=useState('2020');

  async function submit(e){
    e.preventDefault();
    try{
      await API.post('/cars', { owner: null, model, regNo, fuelType: fuel, year });
      alert('Car added');
    }catch(e){ alert('Error'); }
  }

  return (
    <div style={{padding:20}}>
      <h2>Add Car</h2>
      <form onSubmit={submit}>
        <input placeholder='Model' value={model} onChange={e=>setModel(e.target.value)} /><br/>
        <input placeholder='Reg No' value={regNo} onChange={e=>setRegNo(e.target.value)} /><br/>
        <select value={fuel} onChange={e=>setFuel(e.target.value)}><option>Petrol</option><option>Diesel</option><option>Hybrid</option></select><br/>
        <input placeholder='Year' value={year} onChange={e=>setYear(e.target.value)} /><br/>
        <button>Add Car</button>
      </form>
    </div>
  );
}
